import React from "react";
import styles from "./details.module.css";

const Details: React.FC = () => {
  return (
    <div className={styles.wrapper_details}>
      <p className={styles.text}>
        <strong className={styles.bold}>Wax:</strong> Top grade Soy wax that
        delivers a smoke less, consistent burn
      </p>
      <p className={styles.text}>
        <strong className={styles.bold}>Fragrance:</strong> Premium quality
        ingredients with natural essential oils{" "}
      </p>
      <div>
        <span className={styles.text}>
          <strong className={styles.bold}>Burning Time:</strong> 70-75 hours
        </span>
        <span className={styles.text}>
          <strong className={styles.bold}>Dimension:</strong> 10cm x 5cm{" "}
        </span>
        <span className={styles.text}>
          <strong className={styles.bold}>Weight:</strong> 400g{" "}
        </span>
      </div>
    </div>
  );
};

export default Details;
